{
    "level": "A2–B1",
    "intro": "У цьому підрозділі passive voice подано через основні часові моделі: Present, Past і Future у формах Simple, Continuous і Perfect.",
    "rules": [
        {
            "label": "Core Pattern",
            "color": "emerald",
            "text": "Основа незмінна: <strong>be (у потрібному часі) + V3</strong>.",
            "example": "is done / was done / will be done"
        },
        {
            "label": "Continuous",
            "color": "blue",
            "text": "У continuous forms з'являється <strong>being</strong>.",
            "example": "is being done / was being done / will be being done"
        },
        {
            "label": "Perfect",
            "color": "rose",
            "text": "У perfect forms з'являється <strong>been</strong>.",
            "example": "has been done / had been done / will have been done"
        }
    ]
}

{
    "title": "1. Present Tenses (Теперішні часи)",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "<strong>am\/is\/are + V3<\/strong> — регулярні дії, факти",
            "examples": [
                {
                    "en": "English is spoken in many countries.",
                    "ua": "Англійська розмовляється в багатьох країнах."
                },
                {
                    "en": "The rooms are cleaned every day.",
                    "ua": "Кімнати прибираються щодня."
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "blue",
            "description": "<strong>am\/is\/are + being + V3<\/strong> — дії зараз",
            "examples": [
                {
                    "en": "The house is being painted now.",
                    "ua": "Будинок фарбується зараз."
                },
                {
                    "en": "The documents are being prepared.",
                    "ua": "Документи готуються."
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "rose",
            "description": "<strong>has\/have + been + V3<\/strong> — результат",
            "examples": [
                {
                    "en": "The project has been completed.",
                    "ua": "Проєкт завершено."
                },
                {
                    "en": "All tickets have been sold.",
                    "ua": "Усі квитки продано."
                }
            ]
        }
    ]
}

{
    "title": "2. Past Tenses (Минулі часи)",
    "sections": [
        {
            "label": "Past Simple",
            "color": "emerald",
            "description": "<strong>was\/were + V3<\/strong> — дії в минулому",
            "examples": [
                {
                    "en": "The house was built in 1990.",
                    "ua": "Будинок був побудований у 1990 році."
                },
                {
                    "en": "The letters were sent yesterday.",
                    "ua": "Листи надіслали вчора."
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "blue",
            "description": "<strong>was\/were + being + V3<\/strong> — тривала дія в минулому",
            "examples": [
                {
                    "en": "The car was being repaired when I arrived.",
                    "ua": "Машину ремонтували, коли я прийшов."
                },
                {
                    "en": "The rooms were being cleaned all morning.",
                    "ua": "Кімнати прибиралися весь ранок."
                }
            ]
        },
        {
            "label": "Past Perfect",
            "color": "rose",
            "description": "<strong>had + been + V3<\/strong> — дія до іншої минулої",
            "examples": [
                {
                    "en": "The work had been finished before the deadline.",
                    "ua": "Роботу було закінчено до дедлайну."
                },
                {
                    "en": "The tickets had been sold out before we arrived.",
                    "ua": "Квитки були розпродані до нашого приїзду."
                }
            ]
        }
    ]
}

{
    "title": "3. Future Tenses (Майбутні часи)",
    "sections": [
        {
            "label": "Future Simple",
            "color": "emerald",
            "description": "<strong>will be + V3<\/strong> — дії в майбутньому",
            "examples": [
                {
                    "en": "The results will be announced tomorrow.",
                    "ua": "Результати оголосять завтра."
                },
                {
                    "en": "You will be contacted soon.",
                    "ua": "З вами скоро зв'яжуться."
                }
            ]
        },
        {
            "label": "Future Continuous",
            "color": "blue",
            "description": "<strong>will be + being + V3<\/strong> — рідко використовується",
            "examples": [
                {
                    "en": "The house will be being painted tomorrow.",
                    "ua": "Будинок буде фарбуватися завтра."
                }
            ]
        },
        {
            "label": "Future Perfect",
            "color": "rose",
            "description": "<strong>will have + been + V3<\/strong> — буде завершено до...",
            "examples": [
                {
                    "en": "The work will have been completed by Friday.",
                    "ua": "Робота буде завершена до п'ятниці."
                },
                {
                    "en": "All emails will have been sent by 6 PM.",
                    "ua": "Усі листи будуть надіслані до 18:00."
                }
            ]
        }
    ]
}

{
    "title": "4. Зведена таблиця форм",
    "intro": "Формули passive voice у різних часах:",
    "rows": [
        {
            "en": "Present Simple",
            "ua": "am/is/are + V3",
            "note": "The letter is written."
        },
        {
            "en": "Present Continuous",
            "ua": "am/is/are + being + V3",
            "note": "The letter is being written."
        },
        {
            "en": "Present Perfect",
            "ua": "has/have + been + V3",
            "note": "The letter has been written."
        },
        {
            "en": "Past Simple",
            "ua": "was/were + V3",
            "note": "The letter was written."
        },
        {
            "en": "Past Continuous",
            "ua": "was/were + being + V3",
            "note": "The letter was being written."
        },
        {
            "en": "Past Perfect",
            "ua": "had + been + V3",
            "note": "The letter had been written."
        },
        {
            "en": "Future Simple",
            "ua": "will be + V3",
            "note": "The letter will be written."
        },
        {
            "en": "Future Continuous",
            "ua": "will be being + V3",
            "note": "The letter will be being written."
        },
        {
            "en": "Future Perfect",
            "ua": "will have been + V3",
            "note": "The letter will have been written."
        }
    ],
    "warning": "📌 Future Continuous Passive існує, але трапляється рідко."
}

{
    "title": "5. Ключові правила",
    "items": [
        "У всіх часах ядро формули однакове: <strong>be + V3</strong>.",
        "Для Continuous passive додається <strong>being</strong>.",
        "Для Perfect passive додається <strong>been</strong>.",
        "Найважливіше — правильно обрати форму <strong>be</strong> для потрібного часу.",
        "<strong>Future Continuous Passive</strong> існує, але вживається рідко."
    ]
}
